package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;
import static org.mockito.ArgumentMatchers.any;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.internal.bind.ReflectiveTypeAdapterFactory;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Method;
import java.lang.reflect.Type;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class TypeAdapterRuntimeTypeWrapperTest {

  Gson context;
  TypeAdapter<Object> delegate;
  JsonWriter out;
  TypeAdapterRuntimeTypeWrapper<Object> wrapper;

  // Reflection handles for private methods
  private Method getRuntimeTypeIfMoreSpecificMethod;
  private Method isReflectiveMethod;

  @BeforeEach
  void setup() throws Exception {
    context = mock(Gson.class);
    delegate = mock(TypeAdapter.class);
    out = mock(JsonWriter.class);
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(context, delegate, Object.class);

    getRuntimeTypeIfMoreSpecificMethod = TypeAdapterRuntimeTypeWrapper.class.getDeclaredMethod("getRuntimeTypeIfMoreSpecific", Type.class, Object.class);
    getRuntimeTypeIfMoreSpecificMethod.setAccessible(true);

    isReflectiveMethod = TypeAdapterRuntimeTypeWrapper.class.getDeclaredMethod("isReflective", TypeAdapter.class);
    isReflectiveMethod.setAccessible(true);
  }

  // Helper to invoke private getRuntimeTypeIfMoreSpecific
  private Type getRuntimeTypeIfMoreSpecific(Type declaredType, Object value) throws Exception {
    return (Type) getRuntimeTypeIfMoreSpecificMethod.invoke(wrapper, declaredType, value);
  }

  // Helper to invoke private isReflective
  private boolean isReflective(TypeAdapter<?> adapter) throws Exception {
    return (boolean) isReflectiveMethod.invoke(null, adapter);
  }

  @Test
  void write_runtimeTypeSameAsDeclared_usesDelegateWrite() throws Exception {
    Object value = new Object();

    // runtimeType == declared type (Object.class)
    Type runtimeType = Object.class;

    // Spy on wrapper to mock getRuntimeTypeIfMoreSpecific
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);
    doReturn(runtimeType).when(spyWrapper).write(any(), any()); // dummy to avoid unused spy warning

    // Instead of mocking private method, override via spy with doReturn for write method that calls private method
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Type.class, value);

    // Because getRuntimeTypeIfMoreSpecific is private, we cannot mock it directly.
    // So we use reflection to call real method or override using spy with doReturn on write method.
    // Here simpler to call real write but force runtimeType to declared type via reflection:

    // But since mocking private method directly is impossible, call real write with reflection to simulate:

    // Alternative: call write normally and rely on real private method behavior:
    spyWrapper.write(out, value);

    verify(delegate).write(out, value);
    verifyNoMoreInteractions(delegate);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterNotReflective_usesRuntimeTypeAdapter() throws Exception {
    Object value = new String("test");
    Type runtimeType = String.class;

    @SuppressWarnings("unchecked")
    TypeAdapter<Object> runtimeTypeAdapter = mock(TypeAdapter.class);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);

    // Use reflection to override getRuntimeTypeIfMoreSpecific by spying write method and intercepting call
    doReturn(runtimeType).when(spyWrapper).write(any(), any()); // dummy to avoid unused spy warning

    // Setup context.getAdapter to return runtimeTypeAdapter:
    when(context.getAdapter(TypeToken.get(runtimeType))).thenReturn(runtimeTypeAdapter);

    // We cannot mock 'instanceof' directly, so simulate isReflective returning false for runtimeTypeAdapter
    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);
    doReturn(false).when(spyWrapper).isReflective(runtimeTypeAdapter);
    doReturn(false).when(spyWrapper).isReflective(delegate);

    // Because getRuntimeTypeIfMoreSpecific and isReflective are private,
    // we use reflection to override them in spyWrapper:
    // But simpler to override isReflective calls via spy as above.

    spyWrapper.write(out, value);

    verify(runtimeTypeAdapter).write(out, value);
    verifyNoMoreInteractions(delegate);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateNotReflective_usesDelegate() throws Exception {
    Object value = new String("test");
    Type runtimeType = String.class;

    @SuppressWarnings("unchecked")
    TypeAdapter<Object> runtimeTypeAdapter = mock(TypeAdapter.class);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);

    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);
    when(context.getAdapter(TypeToken.get(runtimeType))).thenReturn(runtimeTypeAdapter);

    doReturn(true).when(spyWrapper).isReflective(runtimeTypeAdapter);
    doReturn(false).when(spyWrapper).isReflective(delegate);

    spyWrapper.write(out, value);

    verify(delegate).write(out, value);
    verifyNoMoreInteractions(runtimeTypeAdapter);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateReflective_usesRuntimeTypeAdapter() throws Exception {
    Object value = new String("test");
    Type runtimeType = String.class;

    @SuppressWarnings("unchecked")
    TypeAdapter<Object> runtimeTypeAdapter = mock(TypeAdapter.class);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);

    doReturn(runtimeType).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);
    when(context.getAdapter(TypeToken.get(runtimeType))).thenReturn(runtimeTypeAdapter);

    doReturn(true).when(spyWrapper).isReflective(runtimeTypeAdapter);
    doReturn(true).when(spyWrapper).isReflective(delegate);

    spyWrapper.write(out, value);

    verify(runtimeTypeAdapter).write(out, value);
    verifyNoMoreInteractions(delegate);
  }

  @Test
  void write_nullValue_runtimeTypeSame_usesDelegate() throws Exception {
    Object value = null;

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = Mockito.spy(wrapper);

    doReturn(Object.class).when(spyWrapper).getRuntimeTypeIfMoreSpecific(Object.class, value);

    spyWrapper.write(out, value);

    verify(delegate).write(out, value);
  }
}
